() => {
  const html=document.documentElement.innerHTML;
  const b=document.querySelector('.ml-hero__btn'); const cs=b?getComputedStyle(b):null;
  const out={ theme:(window.Shopify&&Shopify.theme&&Shopify.theme.id)||null,
    bg:cs&&cs.backgroundColor, radius:cs&&cs.borderRadius, fontSize:cs&&cs.fontSize,
    hasMauve: html.indexOf('#9e4c58')>=0, hasMauveImportant: html.indexOf('#9e4c58 !important')>=0,
    inlineStyleBlock: (function(){ var i=html.indexOf('.ml-hero__btn{'); return i>=0? html.slice(i,i+260):'NOT_FOUND'; })(),
    rules:[] };
  const walk=(rules,src)=>{ for(const r of rules){ if(r.type===4){try{walk(r.cssRules,src);}catch(e){}continue;} if(!r.selectorText||!r.style)continue; const bg=r.style.getPropertyValue('background')||r.style.getPropertyValue('background-color'); if(!bg)continue; let m=false; try{m=b.matches(r.selectorText.replace(/::(before|after|marker|placeholder|selection)/g,''));}catch(e){} if(m){ out.rules.push({sel:r.selectorText.slice(0,70), bg:bg, prio:(r.style.getPropertyPriority('background-color')||r.style.getPropertyPriority('background')||''), src:(src||'').split('/').pop().split('?')[0]}); } } };
  for(const s of document.styleSheets){ let rs; try{rs=s.cssRules;}catch(e){continue;} walk(rs, s.href||'inline'); }
  return out;
}
